// Global declarations for pm4py-rust WvdA Soundness Model

// Configuration constants from businessos_gateway.rs
const int TIMEOUT_MS = 5000;
const int MAX_RETRIES = 3;
const int RETRY_DELAY_MS = 100;
const int PREPARE_TIMEOUT_SECS = 30;
const int COMMIT_TIMEOUT_SECS = 60;

// Clock for timeout verification
clock t;

// Message passing channels
chan request, response, prepare, prepare_ack, commit, commit_ack, abort, abort_ack;

// Error types
typedef enum {
    OK, TIMEOUT, CONNECTION_FAILED, RETRY_LIMIT
} ErrorType;

// Transaction states
typedef enum {
    INITIAL, PENDING, PREPARING, COMMITTING, ABORTING, COMMITTED, ABORTED
} TransactionState;

// Participant votes
typedef enum {
    READY, VOTE_ABORT
} ParticipantVote;



    HTTPGateway

    // HTTP Gateway process (simulating discover/conformance/stats endpoints)
    int retry_count = 0;
    int attempts = 0;


        init


        request_ready


        request_sent
        t <= TIMEOUT_MS


        response_received


        timeout


        retry_check


        error


        done







        gateway_ready





        request!
        t=0, retry_count=0





        response?, t < TIMEOUT_MS





        t >= TIMEOUT_MS





        handle_timeout





        retry_count < MAX_RETRIES
        retry_count++, t=0





        retry_count >= MAX_RETRIES





        success





        return_error




    TransactionCoordinator

    // Two-Phase Commit Coordinator
    int participant_ready_count = 0;
    int total_participants = 2;
    TransactionState state = INITIAL;


        init


        pending


        preparing
        t <= PREPARE_TIMEOUT_SECS * 1000


        committing
        t <= COMMIT_TIMEOUT_SECS * 1000


        committed


        aborting


        aborted







        begin_transaction
        state=PENDING





        send_prepare_requests
        state=PREPARING, t=0, participant_ready_count=0





        prepare_ack?, participant_ready_count < total_participants
        participant_ready_count++





        participant_ready_count == total_participants
        state=COMMITTING, t=0





        prepare_abort! || t >= PREPARE_TIMEOUT_SECS * 1000
        state=ABORTING





        commit_ack?
        state=COMMITTED





        t >= COMMIT_TIMEOUT_SECS * 1000
        state=ABORTING





        abort_ack?
        state=ABORTED




    Participant

    // Participant in Two-Phase Commit
    ParticipantVote vote = READY;


        init


        waiting_prepare


        validating
        t <= 1000


        ready


        abort_state


        done







        participant_ready





        prepare?
        t=0





        validation_ok
        vote=READY





        validation_fail
        vote=VOTE_ABORT





        prepare_ack!





        prepare_abort!




// System composition: HTTP Gateway + Coordinator + Participants
gateway = HTTPGateway();
coordinator = TransactionCoordinator();
participant1 = Participant();
participant2 = Participant();

system gateway, coordinator, participant1, participant2;














 gateway.timeout
     Meaning: If timeout elapses in request_sent, transition to timeout occurs
     Expected: PASS (invariant t <= TIMEOUT_MS enforces this)
-->





 coordinator.committed
     (coordinator.preparing && (participant1.abort_state || participant2.abort_state)) --> coordinator.aborted
     Meaning: Atomic decision (all commit or all abort)
     Expected: PASS (coordinator waits for all participants)
-->


 (participant1.done && participant2.done))
     Meaning: Coordinator doesn't commit until all participants acked
     Expected: PASS (synchronous channel communication)
-->
